import{_ as l,I as a,o as i,c,j as e,a as n,J as o}from"./chunks/framework.DYZFTu11.js";const f=JSON.parse('{"title":"《α星篇·其四：在血与火中》","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/novels/shuangxingluji/chapter-06.md","filePath":"zh_cn/novels/shuangxingluji/chapter-06.md","lastUpdated":1773498699000}'),p={name:"zh_cn/novels/shuangxingluji/chapter-06.md"};function d(u,t,h,g,_,m){const s=a("NolebaseGitContributors"),r=a("NolebaseGitChangelog");return i(),c("div",null,[t[0]||(t[0]=e("h1",{id:"《α星篇·其四-在血与火中》",tabindex:"-1"},[e("strong",null,"《α星篇·其四：在血与火中》"),n(),e("a",{class:"header-anchor",href:"#《α星篇·其四-在血与火中》","aria-label":"Permalink to “《α星篇·其四：在血与火中》”"},"​")],-1)),t[1]||(t[1]=e("p",null,[e("strong",null,"《α星篇·其四：在血与火中》"),n(" 幽深的地下通道被黑暗彻底吞噬，寂静如同实质般在空气中流淌，只有微弱的呼吸声在冰冷的混凝土墙壁间回荡，像是濒死者的最后呢喃。幸存者们蜷缩在阴影的角落里，紧绷的肌肉仍未从昨夜的厮杀中松弛下来，每一道伤痕都在无声地提醒着那场血腥的突围。带领他们的老大——那个总是叼着劣质烟卷、嗓音沙哑却总能让人安心的男人——已经永远倒在了黎明前的黑暗中，用生命为他们争取了最后的生机。此刻，沉默如同一块沉重的铅块，压在每个人的胸口，连呼吸都变得艰难。 可灵裔不会等待。 “各位——” 尼尔德的嗓音突然在死寂中炸开，像一柄锋利的匕首刺破凝滞的空气。他的拳头攥得死紧，指节因过度用力而泛出青白色，但那双布满血丝的眼睛却燃烧着近乎疯狂的决心。"),e("strong",null,"“如果我们继续像行尸走肉一样瘫在这里，下一个死的就会是我们！老大用命换来了我们的生机，难道要让它变成一场笑话吗？活下去——这才是对他最好的祭奠！” 话语如火星溅入干燥的枯草，瞬间点燃了幸存者们濒临熄灭的意志。低垂的头颅缓缓抬起，黯淡的眼底重新泛起微弱的光芒。他们彼此对视，无需言语的默契在空气中传递——活下去，无论如何都必须活下去。"),e("br"),n(" 叶子和星溯靠在斑驳的混凝土墙边，冷眼旁观着这一切。叶子嘴角微微上扬，声音轻得几乎像是自言自语：“人类真是有趣，前一秒还像被抽走了灵魂的傀儡，后一秒就能为了一个虚无缥缈的信念重新站起来拼命。”星溯侧目瞥了她一眼，嗤笑一声：“怎么，情报贩子什么时候兼职当哲学家了？” 尼尔德的演讲仍在继续，每一个字都像是砸在地上的铁锤，激起一片行动的浪潮。“……还能动的人，立刻去补给站搜集弹药！没有武器的，负责把伤员送上运输车！快，我们没有时间浪费！” 人群迅速分散，杂乱的脚步声在狭窄的通道内回荡，金属碰撞声、急促的呼吸声交织成一片。叶子和星溯也行动起来，她们蹲下身，从一堆刚挖出的弹药箱中挑拣出几盒还能用的子弹，冰冷的金属在掌心散发着淡淡的火药味。尼尔德匆匆塞给她们几块干硬的粮饼，粗糙的触感硌在掌心，却比任何珍馐都珍贵——在战场上，食物就是生命。 二十分钟后，车队的引擎轰鸣着冲出地下通道，轮胎碾过碎石，扬起一片遮天蔽日的尘土。几乎在同一刻，灵裔部队的身影从荒芜的地平线上浮现，如同潮水般向他们涌来。 “灵裔来了！拦住他们！”哨车上的嘶吼撕破长空。星溯和叶子从车窗探出身子，星溯扣动扳机，枪口骤然腾起数道淡蓝色磁力轨迹，如灵蛇般缠绕着出膛的子弹，子弹划破空气，没入冲锋的灵裔群中，炸开一片血雾。尼尔德猛打方向盘，车身在密集的法术轰炸中左右漂移，像一叶在暴风雨中挣扎的扁舟，随时可能倾覆。 “（宜居星球β粗口），这群家伙的魔力是无限的吗？！”尼尔德咬牙咒骂，汗水顺着额角滑落，浸湿了早已破烂的衣领。剧烈的颠簸让叶子和星溯的准星不断偏移，可她们仍旧精准地击倒了数名逼近的灵裔。其他车辆的火力也在交织，一时间，幸存者们竟隐隐占了上风。 然而，炮火的轰鸣骤然撕裂了短暂的平衡。 “（宜居星球β粗口），是炮击！闪开！”叶子瞳孔骤缩，窗外刺目的火光映亮了她苍白的脸。尼尔德几乎把方向盘拧断，车身猛地侧滑，一枚炮弹在右后方炸开，气浪将一辆运输车掀得腾空而起。金属框架在空中扭曲、解体，燃烧的残骸如雨点般砸落，砸在地上发出令人牙酸的金属哀鸣。 “第三辆车完了！”有人在对讲机里尖叫，声音里带着绝望的颤抖。 灵裔的冲锋号角在烟尘中响起，更多的身影从炮火撕开的缺口中涌来，猩红的眼睛在黑暗中连成一片血色的海洋。星溯咬开一颗手雷的拉环，默数三秒后扬手抛出。爆炸的火光吞没了五六个灵裔，但很快又被后续的黑影填满，仿佛无穷无尽。 整个车队在炮火中溃散，灵裔的嘶吼从四面八方逼近，如同死神的低语，在耳边萦绕不去…… 叶子换上一个新弹匣，忽然眯起眼，声音低沉：“不对劲。”她死死盯着灵裔的阵型，“他们在逼我们转向。” 星溯顺着她的目光看去——灵裔的冲锋看似混乱，却隐隐将车队逼往东侧的峡谷。那里狭窄的隘口像一张等待闭合的巨口，一旦进去，就是死路一条。 “尼尔德！”星溯拍打驾驶座，声音里带着罕见的急促，“不能进峡谷！” “老子知道！”他怒吼着，一脚将油门踩到底。引擎发出濒临崩溃的嘶吼，车身撞开两名拦路的灵裔，硬生生从包围网的缺口冲了出去，轮胎在沙地上划出深深的沟壑。 最后一枚炮弹落在车队尾端，将哨车炸成燃烧的废铁。但幸存者们终于冲出了火力网，将灵裔的嘶吼与大规模法术的嗡鸣甩在身后。 车厢里弥漫着血腥和焦糊味，星溯瘫坐在座位上，发现自己的手指仍在无意识地抽搐，肌肉记忆仍在重复着扣动扳机的动作。叶子慢条斯理地舔掉虎口溅到的血，望向窗外渐暗的天色，眼神晦暗不明。 当最后一缕硝烟散去，幸存者们终于甩开了追兵。可短暂的喘息之后，更残酷的现实摆在眼前——干涸的水壶、空瘪的行囊，以及望不到尽头的荒原。活下来了，可接下来呢？")],-1)),o(s),o(r)])}const x=l(p,[["render",d]]);export{f as __pageData,x as default};
